 28	import { InfoCircleIcon } from '@patternfly/react-icons';
 29	import './alerts.scss';
 30	import { FieldLevelHelp } from '../generic';
 31	
 32	type AlertBadgeProps = {
 33	  alerts: Alert[];
 34	  alertSeverity: AlertSeverity;
 35	  key?: number;
 36	  onToggle: Function;
 37	};
 38	
 39	const AlertBadge: React.FC<AlertBadgeProps> = ({
 40	  alerts,
 41	  alertSeverity,
 42	  key,
 43	  onToggle,
 44	}) => {
 45	  let icon: JSX.Element;
 46	  switch (alertSeverity) {
 47	    case AlertSeverity.Critical:
 48	      icon = <RedExclamationCircleIcon />;
 49	      break;
 50	    case AlertSeverity.Warning:
 51	      icon = <YellowExclamationTriangleIcon />;
 52	      break;
 53	    default:
 54	      icon = <InfoCircleIcon />;
 55	  }
 56	
 57	  const onClick = () => onToggle(`alert-toggle-${alertSeverity}`);
 58	
 59	  return (
 60	    <Button
 61	      variant={ButtonVariant.plain}
 62	      isInline
 63	      onClick={onClick}
 64	      className="odf-alerts-panel__button"
 65	    >
 66	      <Badge
 67	        key={key}
 68	        className={`odf-alerts-panel__badge odf-alerts-panel__badge-${alertSeverity}`}
 69	      >
 70	        <StatusIconAndText title={alerts.length.toString()} icon={icon} />
 71	      </Badge>
 72	      <span className="odf-alerts-panel__badge-text">
 73	        {_.startCase(alertSeverity)}
 74	      </span>
 75	    </Button>
 76	  );
 77	};
 78	
 79	type AlertAccordionItemProps = {
 80	  alerts: React.ComponentProps<typeof AlertItem>['alert'][];
 81	  alertSeverity: AlertSeverity;
 82	  expanded: string;
 83	  loaded: boolean;
 84	  loadError: object;
 85	  onToggle: Function;
 86	  AlertItemComponent?: React.FC<React.ComponentProps<typeof AlertItem>>;
 87	};
 88	
 89	const AlertAccordionItem: React.FC<AlertAccordionItemProps> = ({
 90	  alerts,
 91	  alertSeverity,
 92	  expanded,
 93	  loaded,
 94	  loadError,
 95	  onToggle,
 96	  AlertItemComponent = AlertItem,
 97	}) => {
 98	  const { t } = useCustomTranslation();
 99	  const alertToggleId = `alert-toggle-${alertSeverity}`;
100	  const alertExpandId = `alert-expand-${alertSeverity}`;
101	  return (
102	    <AccordionItem>
103	      <AccordionToggle
104	        onClick={() => onToggle(alertToggleId)}
105	
106	        id={alertToggleId}
107	      >
108	        {`${_.startCase(alertSeverity)} alerts`}
109	      </AccordionToggle>
110	      <AccordionContent
111	        id={alertExpandId}
112	
113	      >
114	        {alerts.length === 0 && !loadError ? (
115	          <div className="centerComponent">
116	            <div className="text-muted">
117	              {t('No {{alertSeverity}} alerts found', { alertSeverity })}
118	            </div>
119	          </div>
120	        ) : (
121	          <AlertsBody error={!_.isEmpty(loadError)}>
122	            {loaded &&
123	              alerts.length > 0 &&
124	              alerts.map((alert) => (
125	                <AlertItemComponent key={alert?.rule?.id} alert={alert} />
126	              ))}
127	          </AlertsBody>
128	        )}
129	      </AccordionContent>
130	    </AccordionItem>
131	  );
132	};
133	
134	type AlertsProps = {
135	  alerts: Alert[];
136	  alertsFilter?: (alert: Alert) => boolean;
137	  className?: string;
138	  AlertItemComponent?: React.FC<React.ComponentProps<typeof AlertItem>>;
139	  titleToolTip?: JSX.Element | string;
140	  loaded: boolean;
141	  loadError: object;
142	};
143	
144	const AlertsPanel: React.FC<AlertsProps> = ({
145	  alerts,
146	  alertsFilter,
147	  className,
148	  AlertItemComponent,
149	  titleToolTip,
150	  loaded,
151	  loadError,
152	}) => {
153	  const { t } = useCustomTranslation();
154	  const [expanded, setExpanded] = React.useState('');
155	  const onToggle = (id: string) => {
156	    if (id === expanded) {
157	      setExpanded('');
158	    } else {
159	      setExpanded(id);
160	    }
161	  };
162	  const filteredAlerts =
163	    loaded && !loadError && !_.isEmpty(alerts)
164	      ? alertsFilter
165	        ? alerts.filter(alertsFilter)
166	        : alerts
167	      : [];
168	  const [criticalAlerts, warningAlerts, infoAlerts] = [[], [], []];
169	  filteredAlerts.forEach((alert: Alert) => {
170	    switch (getAlertSeverity(alert)) {
171	      case AlertSeverity.Critical:
172	        criticalAlerts.push(alert);
173	        break;
174	      case AlertSeverity.Warning:
175	        warningAlerts.push(alert);
176	        break;
177	      default:
178	        infoAlerts.push(alert);
179	    }
180	  });
181	
182	  return (
183	    <div
184	      className={classNames('odf-m-pane__body', 'odf-alerts__panel', className)}
185	    >
186	      <Title headingLevel="h3">
187	        {t('Alerts')} ({filteredAlerts.length})
188	        {!!titleToolTip && <FieldLevelHelp>{titleToolTip}</FieldLevelHelp>}
189	      </Title>
190	      <Divider className="odf-alerts-panel__divider" />
191	      <AlertBadge
192	        alerts={criticalAlerts}
193	        alertSeverity={AlertSeverity.Critical}
194	        onToggle={onToggle}
195	      />
196	      <AlertBadge
197	        alerts={warningAlerts}
198	        alertSeverity={AlertSeverity.Warning}
199	        onToggle={onToggle}
200	      />
201	      <AlertBadge
202	        alerts={infoAlerts}
203	        alertSeverity={AlertSeverity.Info}
204	        onToggle={onToggle}
205	      />
206	      <Divider className="odf-alerts-panel__divider" />
207	      <Accordion asDefinitionList={false}>
208	        <AlertAccordionItem
209	          alerts={criticalAlerts}
210	          alertSeverity={AlertSeverity.Critical}
211	          onToggle={onToggle}
212	          expanded={expanded}
213	          loaded={loaded}
214	          loadError={loadError}
215	          AlertItemComponent={AlertItemComponent}
216	        />
217	        <AlertAccordionItem
218	          alerts={warningAlerts}
219	          alertSeverity={AlertSeverity.Warning}
220	          onToggle={onToggle}
221	          expanded={expanded}
222	          loaded={loaded}
223	          loadError={loadError}
224	          AlertItemComponent={AlertItemComponent}
225	        />
226	        <AlertAccordionItem
227	          alerts={infoAlerts}
228	          alertSeverity={AlertSeverity.Info}
229	          onToggle={onToggle}
230	          expanded={expanded}
231	          loaded={loaded}
232	          loadError={loadError}
233	          AlertItemComponent={AlertItemComponent}
234	        />
235	      </Accordion>
236	    </div>
237	  );
238	};
